-- Nebular Portfolio seed migration 002
-- Seeds galleries, series, and placeholder photos to mirror data/*-static.json

on conflict (slug) do update set title = excluded.title, description = excluded.description, cover_photo_id = excluded.cover_photo_id, order_index = excluded.order_index, published_at = excluded.published_at;

on conflict (slug) do update set title = excluded.title, description = excluded.description, theme_tag = excluded.theme_tag, cover_photo_id = excluded.cover_photo_id, status = excluded.status, status_note = excluded.status_note;

on conflict (id) do update set title = excluded.title, caption = excluded.caption, alt_text = excluded.alt_text, gallery_slug = excluded.gallery_slug;

on conflict (series_slug, photo_id) do update set order_index = excluded.order_index;
