insert into galleries (slug, title, description, cover_photo_id, order_index, published_at) values
  ('vancouver-street', 'Vancouver Street', 'Rainy mornings, late-afternoon light, quiet commuter geometry. Downtown Vancouver and the West End captured on foot, unposed, one frame at a time.', 'ph_001', 1, '2026-01-10T00:00:00Z'),
  ('coal-harbour-waterfront', 'Coal Harbour Waterfront', 'Seawall studies, seaplane departures, cargo cranes at dusk. A slow portrait of the inner harbour across a single season.', 'ph_003', 2, '2026-02-01T00:00:00Z'),
  ('documentary-lagos', 'Documentary Lagos', 'Open-air market studies, return-trip field work. Colour, shadow, texture, commerce. Framed with respect for subjects and scene.', 'ph_005', 3, '2026-02-18T00:00:00Z'),
  ('portraits', 'Portraits', 'Commissioned and editorial portraits. Natural light, mid-frame, conversational.', 'ph_006', 4, '2026-03-01T00:00:00Z'),
  ('quiet-interiors', 'Quiet Interiors', 'Domestic surfaces, hotel lobbies, architectural fragments. Found still lifes in places that were never meant to be photographed.', 'ph_007', 5, '2026-03-12T00:00:00Z'),
  ('craft-fieldwork', 'Craft Fieldwork', 'Tools, hands, process. Long-term project focused on makers and their working surfaces.', 'ph_008', 6, '2026-03-25T00:00:00Z')
