  ('ph_007','quiet-interior-lobby','quiet-interiors','Quiet interior, lobby','Hotel stillness at mid-afternoon. Found still life.','A hotel lobby with warm interior lighting, two chairs, a low table, and empty space; mid-afternoon stillness.','Fujifilm X-T4','XF 16-55mm f/2.8 R LM WR',800,'f/4.0','1/125s',23,'2026-03-14T14:45:00Z','/placeholders/ph_007.svg',1600,1067,'nebular-placeholder-svg','In-house editorial placeholder generated by Nebular Labs.','R ARCHITECTURE (original Unsplash reference)','https://unsplash.com/photos/FQWDEvTq6hQ',array['interior','still-life','quiet'],true),
